import React from 'react';
import { Gradient } from './background.js';

function GradientCanvas() {
  const gradient = new Gradient();
  const [isLagging, setIsLagging] = React.useState(false);

  React.useEffect(() => {
    const checkLag = () => {
      const startTime = performance.now();
      let lagDetected = false;

      const checkFrame = () => {
        const deltaTime = performance.now() - startTime;

        if (deltaTime > 16) { // Adjust the threshold as per your needs
          setIsLagging(true);
          gradient.pause();
          lagDetected = true;
        }

        if (!lagDetected) {
          requestAnimationFrame(checkFrame);
        }
      };

      checkFrame();
    };

    checkLag();

    return () => {
      gradient.resume(); // Resume animation when the component is unmounted
    };
  }, []);

  return (
    <canvas id="gradient-canvas" data-transition-in />
  );
}

export default GradientCanvas;
